const models = $input.all()
  .map((item) => item.json)
  .sort((a, b) => (b.workerCount || 0) - (a.workerCount || 0));

if (models.length === 0) {
  throw new Error('No Sogni LLM models are available right now. Try again later.');
}

const uploadItem = $('Upload Image').first();
const binaryInfo = uploadItem.binary?.artistImage;
if (!binaryInfo) {
  throw new Error('No uploaded image was found in binary.artistImage.');
}

const mimeType = binaryInfo.mimeType || 'image/png';
const fileName = binaryInfo.fileName || 'uploaded-image';
const imageBuffer = await this.helpers.getBinaryDataBuffer(0, 'artistImage');
const dataUrl = `data:${mimeType};base64,${imageBuffer.toString('base64')}`;

const bestModel = models[0];
const messages = [
  {
    role: 'system',
    content: 'You are a concise visual describer. Describe the uploaded image clearly, mention notable subjects, setting, colors, style, and any readable text. If uncertain, say so.'
  },
  {
    role: 'user',
    content: [
      {
        type: 'text',
        text: 'Describe this uploaded image in 120 words or less.'
      },
      {
        type: 'image_url',
        image_url: {
          url: dataUrl,
          detail: 'high'
        }
      }
    ]
  }
];

return {
  json: {
    fileName,
    mimeType,
    modelId: bestModel.id,
    modelName: bestModel.label || bestModel.id,
    workerCount: bestModel.workerCount || 0,
    messages
  }
};

const result = $input.first().json;
const description = String(result.content || '').trim();

if (!description) {
  throw new Error('The Sogni LLM response was empty.');
}

const escapeHtml = (value) => value
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const fileName = String(result.fileName || 'uploaded image');
const modelId = String(result.modelId || 'unknown-model');
const descriptionHtml = escapeHtml(description).replace(/\n/g, '<br>');

return {
  json: {
    ...result,
    completionTitle: 'Image Description',
    completionMessage: `<strong>File:</strong> ${escapeHtml(fileName)}<br><br>${descriptionHtml}<br><br><small>Model: ${escapeHtml(modelId)}</small>`
  }
};
